@Component
public class JwtAuthFilter implements GlobalFilter {
    @Override
    public Mono<Void> filter(ServerWebExchange exchange, GatewayFilterChain chain) {
        String token = exchange.getRequest()
            .getHeaders().getFirst("Authorization");
        if (token == null || !jwtUtil.isValid(token)) {
            exchange.getResponse().setStatusCode(HttpStatus.UNAUTHORIZED);
            return exchange.getResponse().setComplete();
        }
        return chain.filter(exchange);
    }
}

// Resilience4j con Spring Cloud
@Service
public class OrderService {
    @CircuitBreaker(name = "paymentService", fallbackMethod = "fallbackPayment")
    public PaymentResponse processPayment(PaymentRequest req) {
        return paymentClient.charge(req);
    }

    public PaymentResponse fallbackPayment(PaymentRequest req, Exception e) {
        return PaymentResponse.pending("Payment queued for retry");
    }
}

@Service
public class NotificationService {
    @Retry(name = "emailService", fallbackMethod = "fallbackEmail")
    public void sendEmail(String to, String body) {
        emailClient.send(to, body);
    }
}

