@FeignClient(name = "inventory-service")
public interface InventoryClient {
    @GetMapping("/api/stock/{productId}")
    Stock getStock(@PathVariable Long productId);
}

// Uso:
Stock stock = inventoryClient.getStock(productId);

@FeignClient(
    name = "inventory-service",
    fallbackFactory = InventoryFallbackFactory.class
)
public interface InventoryClient {
    @GetMapping("/api/stock/{id}")
    Stock getStock(@PathVariable Long id);
}

@Component
public class InventoryFallbackFactory implements FallbackFactory<InventoryClient> {
    @Override
    public InventoryClient create(Throwable cause) {
        log.error("Inventory service failed", cause);
        return id -> Stock.unavailable();
    }
}
